    const int32_t *padD = attrs->GetAttrPointer<int32_t>(2);
    const int32_t *padH = padD + 1;
    const int32_t *padW = padD + 2;

    int32_t outD = (D + 2 * (*padD) - *kernelD) / *strideD + 1;
    int32_t outH = (H + 2 * (*padH) - *kernelH) / *strideH + 1;
    int32_t outW = (W + 2 * (*padW) - *kernelW) / *strideW + 1;

    // Simple tiling: each core processes one output element per iteration
